#!/usr/bin/env node
// assets/abcjs-basic-min.js → src/components/abcjsSource.ts 변환 스크립트
// 사용: node scripts/bundle-abcjs.js

const fs = require('fs');
const path = require('path');

const inputPath = path.join(__dirname, '..', 'assets', 'abcjs-basic-min.js');
const outputPath = path.join(__dirname, '..', 'src', 'components', 'abcjsSource.ts');

const source = fs.readFileSync(inputPath, 'utf-8');

// 백틱과 ${ } 이스케이프
const escaped = source.replace(/\\/g, '\\\\').replace(/`/g, '\\`').replace(/\$\{/g, '\\${');

const output = `// AUTO-GENERATED by scripts/bundle-abcjs.js — DO NOT EDIT
// Source: abcjs@6.4.2 (https://cdn.jsdelivr.net/npm/abcjs@6.4.2/dist/abcjs-basic-min.js)
export const ABCJS_SOURCE = \`${escaped}\`;
`;

fs.writeFileSync(outputPath, output, 'utf-8');
console.log(`Generated ${outputPath} (${(source.length / 1024).toFixed(1)} KB)`);
